svg.script:
var CURSOR_X = [0, 43.609375, 87.21875, 130.828125, 194.4375, 215, 236];
var TYPE_GAP = 100;
var HOLD_MS = 30000;
var WAIT_MS = 1000;
var BLINK_MS = 500;
var chars = ['c1','c2','c3','c4'];
var cursor = document.getElementById('cursor');
var blinkTimer = null;

function sleep(ms) { return new Promise(function(r) { setTimeout(r, ms); }); }
function setOp(id, v) { var el = document.getElementById(id); if(el) el.setAttribute('opacity', v); }
function setCursorX(idx) { cursor.setAttribute('x', CURSOR_X[idx]); }
function showCursor() { cursor.setAttribute('opacity', '1'); }

function startBlink() {
  var state = true;
  showCursor();
  blinkTimer = setInterval(function() {
    state = !state;
    cursor.setAttribute('opacity', state ? '1' : '0');
  }, BLINK_MS);
}
function stopBlink() {
  if (blinkTimer) { clearInterval(blinkTimer); blinkTimer = null; }
  showCursor();
}

async function run() {
  while (true) {
    chars.forEach(function(id) { setOp(id, '0'); });
    setOp('ch', '0'); setOp('cr', '0');
    setCursorX(0); showCursor();
    await sleep(300);

    stopBlink();
    for (var i = 0; i < 4; i++) {
      setOp(chars[i], '1'); setCursorX(i + 1);
      await sleep(TYPE_GAP);
    }
    setOp('ch', '1'); setCursorX(5); await sleep(TYPE_GAP);
    setOp('cr', '1'); setCursorX(6); await sleep(TYPE_GAP);

    startBlink(); await sleep(HOLD_MS); stopBlink();

    setOp('cr', '0'); setCursorX(5); await sleep(TYPE_GAP);
    setOp('ch', '0'); setCursorX(4); await sleep(TYPE_GAP);
    for (var j = 3; j >= 0; j--) {
      setOp(chars[j], '0'); setCursorX(j);
      await sleep(TYPE_GAP);
    }
    startBlink(); await sleep(WAIT_MS); stopBlink();
  }
}

run();
